// Получаем данные из Postgres
const items = $input.all();

const buttons = items.map(item => ({
  text: `📁 ${item.json.title}`,
  callback_data: `select_topic:${item.json.id}`
}));

// Кнопка создания нового
buttons.push({
  text: '➕ Создать новый топик',
  callback_data: 'action:create_new'
});

// Группируем по 2 в ряд
const rows = [];
while (buttons.length) {
  rows.push(buttons.splice(0, 2));
}


return [
  {
    json: {
      chat_id: $('Telegram Trigger').first().json.message.from.id,
      inline_keyboard: rows
    }
  }
];

parameters.query:
SELECT state, created_at
FROM gnote.user_state
WHERE user_id = {{ $json.message.from.id }}
LIMIT 1;

WITH inserted AS (
  INSERT INTO gnote.topics (title, user_id)
  VALUES (
    '{{ $("Telegram Trigger").first().json.message.text.replace(/'/g, "''") }}',
    {{ $("Telegram Trigger").first().json.message.from.id }}
  )
  ON CONFLICT DO NOTHING
  RETURNING id, title, user_id
),
existing AS (
  SELECT id, title, user_id
  FROM gnote.topics
  WHERE user_id = {{ $("Telegram Trigger").first().json.message.from.id }}
    AND LOWER(title) = LOWER('{{ $("Telegram Trigger").first().json.message.text.replace(/'/g, "''") }}')
  LIMIT 1
),
clear_state AS (
  DELETE FROM gnote.user_state
  WHERE user_id = {{ $("Telegram Trigger").first().json.message.from.id }}
)
SELECT *
FROM inserted
UNION ALL
SELECT *
FROM existing
LIMIT 1;

