const input = $input.first().json;

const state = input.state
  ? String(input.state).trim()
  : 'no_state';

return [
  {
    json: {
      ...input,
      state
    }
  }
];

const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query, but received message');
}

const data = input.callback_query.data;
// пример: select_topic:18

const topicId = Number(data.split(':')[1]);
const userId = input.callback_query.from.id;

return [
  {
    json: {
      user_id: userId,
      topic_id: topicId,
      callback_query_id: input.callback_query.id,
      chat_id: input.callback_query.from.id
    }
  }
];

const items = $input.all();

const validTopics = items.filter(item => item.json.id && item.json.title);

if (validTopics.length === 0) {
  return [
    {
      json: {
        chat_id: $('Telegram Trigger').first().json.message.chat.id,
        text: "У тебя пока нет топиков.\n\nНажми ➕ Создать новый топик, когда будешь сохранять сообщение."
      }
    }
  ];
}

const lines = validTopics.map((item, index) => {
  const title = item.json.title;
  const count = Number(item.json.messages_count || 0);

  return `${index + 1}. 📁 ${title} — ${count} ${count === 1 ? 'message' : 'messages'}`;
});

return [
  {
    json: {
      chat_id: $('Telegram Trigger').first().json.message.chat.id,
      text: `📚 Твои топики:\n\n${lines.join('\n')}`
    }
  }
];

const items = $input.all();

const topics = items.filter(item => item.json.id && item.json.title);

const chatId = $('Telegram Trigger').first().json.message.chat.id;

if (topics.length === 0) {
  return [
    {
      json: {
        chat_id: chatId,
        text: 'У тебя пока нет топиков 📭'
      }
    }
  ];
}

const buttons = topics.map(item => {
  const title = item.json.title;
  const count = Number(item.json.messages_count || 0);

  return {
    text: `📁 ${title} (${count})`,
    callback_data: `get_topic:${item.json.id}`
  };
});

const rows = [];
while (buttons.length) {
  rows.push(buttons.splice(0, 1)); // лучше по 1 кнопке в ряд, так читаемее
}

return [
  {
    json: {
      chat_id: chatId,
      text: 'Выбери топик, из которого показать сообщения:',
      inline_keyboard: rows
    }
  }
];

const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query');
}

const data = input.callback_query.data;
// пример: get_topic:18

const topicId = Number(data.split(':')[1]);

if (!topicId) {
  throw new Error(`Invalid topic id in callback data: ${data}`);
}

return [
  {
    json: {
      user_id: input.callback_query.from.id,
      chat_id: input.callback_query.message.chat.id,
      topic_id: topicId,
      callback_query_id: input.callback_query.id
    }
  }
];

const items = $input.all();

if (items.length === 0) {
  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: $('Telegram Trigger').first().json.callback_query.message.chat.id,
          text: 'Топик не найден ⚠️'
        }
      }
    }
  ];
}

return items.map(item => {
  const data = item.json;

  const chatId = data.chat_id;
  const messageType = data.message_type || 'text';

  if (messageType === 'empty' || (!data.content && !data.file_id)) {
    return {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: chatId,
          text: 'В этом топике пока нет сообщений 📭'
        }
      }
    };
  }

  // Text message
  if (messageType === 'text' || !data.file_id) {
    return {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: chatId,
          text: data.content || ''
        }
      }
    };
  }

  const displayName =
    data.file_name ||
    data.caption ||
    data.content ||
    `[${messageType}]`;

  // Photo: show real photo preview + download button
  if (messageType === 'photo') {
    return {
      json: {
        api_method: 'sendPhoto',
        body: {
          chat_id: chatId,
          photo: data.file_id,
          caption: data.caption || '',
          reply_markup: {
            inline_keyboard: [
              [
                {
                  text: 'download',
                  callback_data: `download_msg:${data.id}`
                }
              ]
            ]
          }
        }
      }
    };
  }

  // Any other file: show universal icon + file name, button only says "download"
  return {
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: chatId,
        text: `📎 ${displayName}`,
        reply_markup: {
          inline_keyboard: [
            [
              {
                text: 'download',
                callback_data: `download_msg:${data.id}`
              }
            ]
          ]
        }
      }
    }
  };
});

const msg = $('Telegram Trigger').first().json.message;

if (!msg) {
  throw new Error('No Telegram message found');
}

let messageType = 'text';
let content = msg.text || '';
let fileId = null;
let fileUniqueId = null;
let fileName = null;
let mimeType = null;
let caption = msg.caption || null;

// Photo
if (msg.photo && msg.photo.length > 0) {
  messageType = 'photo';

  // Telegram sends several sizes. The last one is usually the largest.
  const photo = msg.photo[msg.photo.length - 1];

  fileId = photo.file_id;
  fileUniqueId = photo.file_unique_id;
  content = caption || '[photo]';
}

// Document / file
else if (msg.document) {
  messageType = 'document';

  fileId = msg.document.file_id;
  fileUniqueId = msg.document.file_unique_id;
  fileName = msg.document.file_name || null;
  mimeType = msg.document.mime_type || null;
  content = caption || fileName || '[document]';
}

// Video
else if (msg.video) {
  messageType = 'video';

  fileId = msg.video.file_id;
  fileUniqueId = msg.video.file_unique_id;
  fileName = msg.video.file_name || null;
  mimeType = msg.video.mime_type || null;
  content = caption || '[video]';
}

// Voice
else if (msg.voice) {
  messageType = 'voice';

  fileId = msg.voice.file_id;
  fileUniqueId = msg.voice.file_unique_id;
  mimeType = msg.voice.mime_type || null;
  content = caption || '[voice message]';
}

// Audio
else if (msg.audio) {
  messageType = 'audio';

  fileId = msg.audio.file_id;
  fileUniqueId = msg.audio.file_unique_id;
  fileName = msg.audio.file_name || null;
  mimeType = msg.audio.mime_type || null;
  content = caption || fileName || '[audio]';
}

// Sticker
else if (msg.sticker) {
  messageType = 'sticker';

  fileId = msg.sticker.file_id;
  fileUniqueId = msg.sticker.file_unique_id;
  content = msg.sticker.emoji ? `[sticker ${msg.sticker.emoji}]` : '[sticker]';
}

// Fallback for unsupported message types
if (!content && !fileId) {
  content = '[unsupported message]';
  messageType = 'unsupported';
}

return [
  {
    json: {
      user_id: msg.from.id,
      user_name: msg.from.first_name || '',
      chat_id: msg.chat.id,
      content,
      message_type: messageType,
      file_id: fileId,
      file_unique_id: fileUniqueId,
      file_name: fileName,
      mime_type: mimeType,
      caption
    }
  }
];

const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query');
}

const data = input.callback_query.data;
// пример: download_msg:123

const messageId = Number(data.split(':')[1]);

if (!messageId) {
  throw new Error(`Invalid message id in callback data: ${data}`);
}

return [
  {
    json: {
      user_id: input.callback_query.from.id,
      chat_id: input.callback_query.message.chat.id,
      message_id: messageId,
      callback_query_id: input.callback_query.id
    }
  }
];

const items = $input.all();

if (items.length === 0) {
  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: $('Telegram Trigger').first().json.callback_query.message.chat.id,
          text: 'Файл не найден или у тебя нет доступа ⚠️'
        }
      }
    }
  ];
}

const data = items[0].json;

const chatId = data.chat_id;
const messageType = data.message_type || 'document';

const caption =
  data.caption ||
  data.file_name ||
  data.content ||
  '';

if (messageType === 'photo') {
  const body = {
    chat_id: chatId,
    photo: data.file_id
  };

  if (data.caption) {
    body.caption = data.caption;
  }

  return {
    json: {
      api_method: 'sendPhoto',
      body
    }
  };
}

if (messageType === 'video') {
  return [
    {
      json: {
        api_method: 'sendVideo',
        body: {
          chat_id: chatId,
          video: data.file_id,
          caption
        }
      }
    }
  ];
}

if (messageType === 'voice') {
  return [
    {
      json: {
        api_method: 'sendVoice',
        body: {
          chat_id: chatId,
          voice: data.file_id,
          caption
        }
      }
    }
  ];
}

if (messageType === 'audio') {
  return [
    {
      json: {
        api_method: 'sendAudio',
        body: {
          chat_id: chatId,
          audio: data.file_id,
          caption
        }
      }
    }
  ];
}

// PDF, Word, Excel, обычный файл
return [
  {
    json: {
      api_method: 'sendDocument',
      body: {
        chat_id: chatId,
        document: data.file_id,
        caption
      }
    }
  }
];
